  ('heelevel3-0c700c30-moex-00132', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-111-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '假設口罩市場的均衡數量與價格由供需雙方共同決定，其市場需求曲線為Qd=10-P，市場供給曲 線為Qs=P-2，其中P為口罩的價格，請問此時若政府對口罩市場中的價格制定價格上限P=5， 以下敘述何者正確？', '["政府制定價格上限後，消費者剩餘上升2.5", "政府制定價格上限後，消費者剩餘上升3.5", "政府制定價格上限後，消費者剩餘下降 3.5", "政府制定價格上限後，消費者剩餘下降2.5"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:05+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "325", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00133', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-111-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '某工廠之生產函數為Q(L,K)=L0.8K0.2，其中Q為產量，L與K分別為勞動與資本，每單位勞動 價格為1，每單位資本價格為2，請問在成本極小化之目標下，投入勞動和資本的最適比例（L/K） 為何？', '["4", "0.25", "8", "0.125"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:05+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "325", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00134', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-111-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '兩家電信公司的長途通話費可以設定為每分鐘$3或$4，下表顯示報償矩陣。則A、B廠商的優勢 策略分別為何？ A廠商的策略 $4 $3 $320萬 $500萬 $4 $320萬 $200萬 B廠商的策略 $200萬 $450萬 $3 $500萬 $450萬', '["$3；$3", "$3；$4", "$4；$3", "$4；$4"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:05+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "325", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00135', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-111-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '有關獨占之敘述，下列何者正確？', '["航空公司對於頭等艙與經濟艙訂定不同票價，係因其採取差別定價", "因為供給量與市場價格不存在一對一關係，所以獨占廠商無供給曲線", "與完全競爭的廠商相比，獨占廠商的產量較多，售價較低", "獨占廠商利潤極大點須滿足「產品價格等於邊際成本」條件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:05+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "325", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00136', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-111-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '假設在某一個國家，其15歲以上的人口為500,000人，勞動力人口為300,000人。在勞動力人口 中，就業人口為240,000人，失業人口為60,000。請問勞動參與率為何？', '["25%", "48%", "55%", "60% 32260、32560 32960、33060"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:05+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "325", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00137', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-111-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '如果勞動與資本投入是互補的，某廠商今年的生產設備故障率顯著高於去年，在追求利潤極大的 考量下，相對於去年，今年廠商應：', '["裁減員工", "增聘員工", "提高工資", "停止生產"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:05+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "325", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00138', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-111-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '假設某一廠商為完全競爭廠商，其短期成本函數為TC(Q)=100+aQ+bQ2，其中a＞0且b＞0，此 一廠商之短期供給曲線為何？', '["P=a+bQ，P≧a", "P=a+2bQ，P≧a", "P=a+bQ，P≧0", "P=a+2bQ，P≧0"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:05+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "325", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
  ('heelevel3-0c700c30-moex-00139', 'heelevel3-0c700c30', 'heelevel3-0c700c30-moex-111-d3ff7f6b', 'sub-heelevel3-0c700c30-03', NULL, 'single_choice', '下列何者不是資訊不對稱時，所產生的道德風險行為？', '["小偷在偷竊財物時面對被抓的風險", "車子投保竊盜險之後，車主就不再將車門上鎖", "金融保險機構的經理人使用公司的資金購置過高風險的資產", "員工上班趁主管不注意時，使用手機處理私人事務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:05+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "325", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "統計"}'::jsonb, NULL),
